// ============================================================================
// Confetti Helper
// ============================================================================

const launchConfetti = () => {
  const duration = 2000;
  const end = Date.now() + duration;
  const frame = () => {
    confetti({ particleCount: 3, angle: 60, spread: 55, origin: { x: 0, y: 0.7 }, colors: ['#FF6B9D', '#FFDEE9', '#B5FFFC', '#FFD700'] });
    confetti({ particleCount: 3, angle: 120, spread: 55, origin: { x: 1, y: 0.7 }, colors: ['#FF6B9D', '#FFDEE9', '#B5FFFC', '#FFD700'] });
    if (Date.now() < end) requestAnimationFrame(frame);
  };
  frame();
};

// ============================================================================
// Floating Hearts Background
// ============================================================================

const FloatingHearts = () => {
  const hearts = useMemo(() =>
    [...Array(14)].map((_, i) => ({
      id: i,
      emoji: ['💕', '💖', '💗', '🌸', '✨', '💓'][i % 6],
      left: `${(i * 7 + 5) % 100}%`,
      delay: (i % 5) * 0.8,
      duration: 5 + (i % 4),
      size: 14 + (i % 3) * 6,
    })), []);

  return (
    <div style={{ position: 'fixed', inset: 0, pointerEvents: 'none', overflow: 'hidden', zIndex: 0 }}>
      {hearts.map(h => (
        <motion.div
          key={h.id}
          style={{ position: 'absolute', left: h.left, bottom: '-30px', fontSize: h.size }}
          animate={{ y: [0, -window.innerHeight - 60], opacity: [0.7, 0] }}
          transition={{ duration: h.duration, repeat: Infinity, delay: h.delay, ease: 'linear' }}
        >
          {h.emoji}
        </motion.div>
      ))}
    </div>
  );
};

